export async function main(_ctx, _input) {
  let randomThrew = false, randomErrName = 'none';
  try { Math.random(); } catch (e) { randomThrew = true; randomErrName = e.name; }
  return { ok: true, value: {
    sqrt: Math.sqrt(2), round: Math.round(2.5), roundNeg: Math.round(-2.5),
    trunc: Math.trunc(-4.7), sign: Math.sign(-3), hypot: Math.hypot(3, 4),
    clz32: Math.clz32(1), fround: Math.fround(1.1),
    randomThrew, randomErrName, cbrt: Math.cbrt(27), maxSafe: Number.MAX_SAFE_INTEGER
  } };
}
